import{_ as t,c as o,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"プライバシー: 安全設定 | opencode-supermemory","description":"学習します：private タグでセンシティブ情報を検閲し、API Key を安全に設定する方法を解説。データ保護の基本を習得。","frontmatter":{"title":"プライバシー: 安全設定 | opencode-supermemory","sidebarTitle":"プライバシー","subtitle":"プライバシーとデータセキュリティ：センシティブな情報を保護する方法","description":"学習します：private タグでセンシティブ情報を検閲し、API Key を安全に設定する方法を解説。データ保護の基本を習得。","tags":["プライバシー","セキュリティ","設定"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ja/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"ja/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),s={name:"ja/supermemoryai/opencode-supermemory/security/privacy/index.md"};function i(n,e,d,c,l,p){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="プライバシーとデータセキュリティ-センシティブな情報を保護する方法" tabindex="-1">プライバシーとデータセキュリティ：センシティブな情報を保護する方法 <a class="header-anchor" href="#プライバシーとデータセキュリティ-センシティブな情報を保護する方法" aria-label="Permalink to &quot;プライバシーとデータセキュリティ：センシティブな情報を保護する方法&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><ul><li><strong>データがどこに行くのかを理解</strong>：どのデータがクラウドにアップロードされ、どのデータがローカルに残るのかを明確に把握します。</li><li><strong>検閲テクニックを習得</strong>：<code>&lt;private&gt;</code> タグを使用して、パスワードやキーなどのセンシティブな情報がアップロードされないようにする方法を学びます。</li><li><strong>キーを安全に管理</strong>：<code>SUPERMEMORY_API_KEY</code> を最も安全な方法で設定します。</li></ul><h2 id="基本的な考え方" tabindex="-1">基本的な考え方 <a class="header-anchor" href="#基本的な考え方" aria-label="Permalink to &quot;基本的な考え方&quot;">​</a></h2><p>opencode-supermemory を使用する場合、データフローを理解することが非常に重要です：</p><ol><li><strong>クラウド保存</strong>：あなたの記憶（Memories）は Supermemory のクラウドデータベースに保存され、ローカルファイルではありません。つまり、記憶にアクセスするにはネットワーク接続が必要です。</li><li><strong>ローカル検閲</strong>：プライバシーを保護するため、プラグインはデータをクラウドに送信する<strong>前に</strong>、ローカルで検閲処理を行います。</li><li><strong>明示的な制御</strong>：プラグインはすべてのファイルを自動的にスキャンしてアップロードするのではなく、Agent が <code>add</code> ツールを明示的に呼び出すか、圧縮がトリガーされた場合にのみ、関連するコンテンツが処理されます。</li></ol><h3 id="検閲メカニズム" tabindex="-1">検閲メカニズム <a class="header-anchor" href="#検閲メカニズム" aria-label="Permalink to &quot;検閲メカニズム&quot;">​</a></h3><p>プラグインには <code>&lt;private&gt;</code> タグを識別するためのシンプルなフィルターが内蔵されています。</p><ul><li><strong>入力</strong>：<code>ここでのデータベースパスワードは &lt;private&gt;123456&lt;/private&gt; です</code></li><li><strong>処理</strong>：プラグインがタグを検出し、その内容を <code>[REDACTED]</code> に置換します。</li><li><strong>アップロード</strong>：<code>ここでのデータベースパスワードは [REDACTED] です</code></li></ul><div class="info custom-block"><p class="custom-block-title">ヒント</p><p>この処理プロセスはプラグインの内部コードで実行され、データがコンピューターを離れる前に完了します。</p></div><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ-1-api-key-を安全に設定" tabindex="-1">ステップ 1：API Key を安全に設定 <a class="header-anchor" href="#ステップ-1-api-key-を安全に設定" aria-label="Permalink to &quot;ステップ 1：API Key を安全に設定&quot;">​</a></h3><p>設定ファイルに API Key を直接書き込むことはできますが、誤って設定ファイルを他の人と共有してしまうのを防ぐため、優先順位のロジックを理解することをお勧めします。</p><p><strong>優先順位ルール</strong>：</p><ol><li><strong>設定ファイル</strong> (<code>~/.config/opencode/supermemory.jsonc</code>)：優先順位が最も高い。</li><li><strong>環境変数</strong> (<code>SUPERMEMORY_API_KEY</code>)：設定ファイルで設定されていない場合、この変数が使用されます。</li></ol><p><strong>推奨される方法</strong>： 柔軟に切り替えたり、CI/CD 環境で使用したりしたい場合、環境変数を使用します。個人開発者の場合、ユーザーディレクトリの JSONC ファイルに設定しても安全です（プロジェクトの Git リポジトリには含まれないため）。</p><h3 id="ステップ-2-private-タグを使用する" tabindex="-1">ステップ 2：<code>&lt;private&gt;</code> タグを使用する <a class="header-anchor" href="#ステップ-2-private-タグを使用する" aria-label="Permalink to &quot;ステップ 2：`&lt;private&gt;` タグを使用する&quot;">​</a></h3><p>対話で自然言語を使用して Agent にセンシティブな情報を含む内容を記憶させたい場合、<code>&lt;private&gt;</code> タグでセンシティブな部分を囲むことができます。</p><p><strong>操作のデモ</strong>：</p><p>Agent に教えてください：</p><blockquote><p>生産環境のデータベース IP は 192.168.1.10 ですが、root パスワードは <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code> です。パスワードを漏らさないでください。</p></blockquote><p><strong>期待される出力</strong>： Agent は <code>supermemory</code> ツールを呼び出して記憶を保存します。Agent の返信にはパスワードが含まれるかもしれません（コンテキスト内にあるため）が、<strong>実際に Supermemory クラウドに保存される記憶</strong>はすでに検閲されています。</p><h3 id="ステップ-3-検閲結果を確認" tabindex="-1">ステップ 3：検閲結果を確認 <a class="header-anchor" href="#ステップ-3-検閲結果を確認" aria-label="Permalink to &quot;ステップ 3：検閲結果を確認&quot;">​</a></h3><p>検索を行って、先ほどのパスワードが本当に保存されていないか確認できます。</p><p><strong>操作</strong>： Agent に先ほどの記憶を検索させます：</p><blockquote><p>生産環境のデータベースのパスワードを検索してください。</p></blockquote><p><strong>期待される結果</strong>： Agent が Supermemory から取得した内容は以下のようになるはずです： <code>生産環境のデータベース IP は 192.168.1.10 ですが、root パスワードは [REDACTED]...</code></p><p>Agent が「パスワードは [REDACTED] です」と教えてくれた場合、検閲メカニズムが正常に動作していることを示しています。</p><h2 id="よくある誤解" tabindex="-1">よくある誤解 <a class="header-anchor" href="#よくある誤解" aria-label="Permalink to &quot;よくある誤解&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">誤解 1：すべてのコードがアップロードされる</p><p><strong>事実</strong>：プラグインは<strong>コードベース全体を自動的にアップロードしません</strong>。<code>/supermemory-init</code> を実行して初期化スキャンを行うか、Agent が特定のコードロジックを「覚える」ことを明示的に決定した場合にのみ、その特定のフラグメントがアップロードされます。</p></div><div class="warning custom-block"><p class="custom-block-title">誤解 2：.env ファイルが自動的に読み込まれる</p><p><strong>事実</strong>：プラグインはプロセス環境の <code>SUPERMEMORY_API_KEY</code> を読み込みます。プロジェクトのルートディレクトリに <code>.env</code> ファイルを置いても、使用しているターミナルまたは OpenCode メインプログラムが読み込まない限り、プラグインは<strong>自動的に読み込みません</strong>。</p></div><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>プライバシー検閲ロジック</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>API Key の読み込み</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>プラグイン呼び出しの検閲</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>重要な関数</strong>：</p><ul><li><code>stripPrivateContent(content)</code>: 正規表現置換を実行し、<code>&lt;private&gt;</code> の内容を <code>[REDACTED]</code> に変更します。</li><li><code>loadConfig()</code>: ローカル設定ファイルをロードし、優先順位は環境変数より高いです。</li></ul></details><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>おめでとうございます！opencode-supermemory のコアコースを完了しました！</p><p>次は以下を続けて学習できます：</p><ul><li><a href="/docs/opencodedocs/ja/supermemoryai/opencode-supermemory/advanced/configuration/">詳細設定</a> に戻って、その他のカスタマイズオプションを確認</li></ul></blockquote>',35)])])}const u=t(s,[["render",i]]);export{m as __pageData,u as default};
